-- H2 2.3.232; 
;              
CREATE USER IF NOT EXISTS "" SALT '' HASH '' ADMIN;            
CREATE CACHED TABLE "PUBLIC"."RUNS"(
    "RUN_ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 3) NOT NULL,
    "STARTED_AT" TIMESTAMP,
    "STOPPED_AT" TIMESTAMP,
    "IMPORTED_AT" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "NOTE" CHARACTER VARYING(2048),
    "HOST_USER" CHARACTER VARYING(64),
    "HOST_NAME" CHARACTER VARYING(255),
    "HOST_TARGET" CHARACTER VARYING(255),
    "HOST_OS" CHARACTER VARYING(128),
    "HOST_TYPE" CHARACTER VARYING(255),
    "HOST_KERNEL" CHARACTER VARYING(128),
    "HOST_CPU" CHARACTER VARYING(255),
    "HOST_GPU" CHARACTER VARYING(255),
    "HOST_MEMORY" CHARACTER VARYING(64),
    "NUM_ITERATIONS" INTEGER,
    "TESTS_RUN" CHARACTER VARYING(512),
    "DESCRIPTION" CHARACTER VARYING(1024),
    "RUN_IDENTIFIER" CHARACTER VARYING(255),
    "DROP_OS_FILESYSTEM_CACHES" BOOLEAN,
    "USE_CONTAINER_HOST_NETWORK" BOOLEAN,
    "DEPLOY_RUN_ID" CHARACTER VARYING(48),
    "DEPLOY_COMMIT" CHARACTER VARYING(64),
    "DEPLOY_SHORT_COMMIT" CHARACTER VARYING(16),
    "DEPLOY_BRANCH" CHARACTER VARYING(128),
    "DEPLOY_DIRTY" BOOLEAN,
    "DEPLOYED_AT" TIMESTAMP,
    "JVM_VERSION" CHARACTER VARYING(128),
    "JVM_HOME" CHARACTER VARYING(255),
    "GRAALVM_VERSION" CHARACTER VARYING(128),
    "GRAALVM_HOME" CHARACTER VARYING(255),
    "MANDREL_VERSION" CHARACTER VARYING(128),
    "MANDREL_HOME" CHARACTER VARYING(255),
    "DOTNET_VERSION" CHARACTER VARYING(64),
    "DOTNET_HOME" CHARACTER VARYING(255),
    "DOTNET_GC_HEAP_HARD_LIMIT" CHARACTER VARYING(64),
    "JVM_MEMORY" CHARACTER VARYING(255),
    "JVM_ARGS" CHARACTER VARYING(2048),
    "QUARKUS_VERSION" CHARACTER VARYING(64),
    "QUARKUS_BUILD_CONFIG_ARGS" CHARACTER VARYING(2048),
    "QUARKUS_NATIVE_BUILD_OPTIONS" CHARACTER VARYING(2048),
    "CPU_APP" CHARACTER VARYING(64),
    "CPU_DB" CHARACTER VARYING(64),
    "CPU_LOAD_GENERATOR" CHARACTER VARYING(64),
    "CPU_FIRST_REQUEST" CHARACTER VARYING(64),
    "CPU_MONITOR" CHARACTER VARYING(64),
    "CPU_OTEL" CHARACTER VARYING(64),
    "APP_CPUS" INTEGER,
    "PROFILER_NAME" CHARACTER VARYING(32),
    "PROFILER_EVENTS" CHARACTER VARYING(64)
);           
ALTER TABLE "PUBLIC"."RUNS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_2" PRIMARY KEY("RUN_ID");      
-- 2 +/- SELECT COUNT(*) FROM PUBLIC.RUNS;     
CREATE CACHED TABLE "PUBLIC"."RUNTIME_RESULTS"(
    "RUN_ID" BIGINT NOT NULL,
    "RUNTIME_NAME" CHARACTER VARYING(64) NOT NULL
);             
ALTER TABLE "PUBLIC"."RUNTIME_RESULTS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_D" PRIMARY KEY("RUN_ID", "RUNTIME_NAME");           
-- 8 +/- SELECT COUNT(*) FROM PUBLIC.RUNTIME_RESULTS;          
CREATE CACHED TABLE "PUBLIC"."ITERATION_METRICS"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 192) NOT NULL,
    "RUN_ID" BIGINT NOT NULL,
    "RUNTIME_NAME" CHARACTER VARYING(64) NOT NULL,
    "ITERATION" INTEGER NOT NULL,
    "METRIC_NAME" CHARACTER VARYING(64) NOT NULL,
    "METRIC_VALUE" DOUBLE PRECISION,
    "UNIT" CHARACTER VARYING(16)
);      
ALTER TABLE "PUBLIC"."ITERATION_METRICS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_A" PRIMARY KEY("ID");             
-- 191 +/- SELECT COUNT(*) FROM PUBLIC.ITERATION_METRICS;      
CREATE INDEX "PUBLIC"."IDX_METRICS_LOOKUP" ON "PUBLIC"."ITERATION_METRICS"("RUN_ID" NULLS FIRST, "RUNTIME_NAME" NULLS FIRST, "METRIC_NAME" NULLS FIRST);       
CREATE INDEX "PUBLIC"."IDX_METRICS_METRIC_NAME" ON "PUBLIC"."ITERATION_METRICS"("METRIC_NAME" NULLS FIRST);    
ALTER TABLE "PUBLIC"."ITERATION_METRICS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_A0" FOREIGN KEY("RUN_ID", "RUNTIME_NAME") REFERENCES "PUBLIC"."RUNTIME_RESULTS"("RUN_ID", "RUNTIME_NAME") ON DELETE CASCADE NOCHECK;              
ALTER TABLE "PUBLIC"."RUNTIME_RESULTS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_D7" FOREIGN KEY("RUN_ID") REFERENCES "PUBLIC"."RUNS"("RUN_ID") ON DELETE CASCADE NOCHECK;           
